package cmd

import (
	"fmt"
	"os"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/server"
	"github.com/spf13/cobra"
)

// resolveTsnetAuthKey applies auth key precedence:
// TS_AUTHKEY env var > --tsnet-auth-key CLI flag > config file auth_key.
// The env var is preferred because CLI flags are visible in ps/history.
func resolveTsnetAuthKey(envKey, flagKey, configKey string) string {
	if envKey != "" {
		return envKey
	}
	if flagKey != "" {
		return flagKey
	}
	return configKey
}

// defaultTsnetHostname returns "ddx-<short-hostname>" for the current host,
// falling back to "ddx" when the hostname is unavailable or empty.
func defaultTsnetHostname() string {
	h, err := os.Hostname()
	if err != nil || h == "" {
		return "ddx"
	}
	// Trim any trailing domain so the ts-net name stays short and stable.
	if i := strings.Index(h, "."); i >= 0 {
		h = h[:i]
	}
	return "ddx-" + h
}

func (f *CommandFactory) newServerCommand() *cobra.Command {
	var port int
	var addr string
	var tlsCert string
	var tlsKey string
	var tsnetEnabled bool
	var tsnetHostname string
	var tsnetAuthKey string
	var hubMode bool
	var federationAllowPlainHTTP bool
	var hubURL string
	var federationSelfURL string

	cmd := &cobra.Command{
		Use:   "server",
		Short: "Start the DDx HTTP and MCP server",
		Long: `Start the DDx server exposing documents, beads, document graph,
and agent session logs over HTTP REST and MCP endpoints.

HTTP API:
  GET /api/health              Liveness check
  GET /api/ready               Readiness check with dependency status
  GET /api/documents           List library documents (?type=)
  GET /api/documents/:path     Read a document
  GET /api/search?q=           Full-text search across documents
  GET /api/personas/:role      Resolve persona for a role
  GET /api/beads               List beads (?status=&label=)
  GET /api/beads/:id           Show a specific bead
  GET /api/beads/ready         List ready beads
  GET /api/beads/blocked       List blocked beads
  GET /api/beads/status        Bead summary counts
  GET /api/beads/dep/tree/:id  Dependency tree for a bead
  GET /api/docs/graph          Document dependency graph
  GET /api/docs/stale          Stale documents
  GET /api/docs/:id            Document metadata and staleness
  GET /api/docs/:id/deps       Upstream dependencies
  GET /api/docs/:id/dependents Downstream dependents
  GET /api/agent/sessions      List agent sessions (?harness=&since=)
  GET /api/agent/sessions/:id  Session detail
  GET /api/metrics/summary     Process metrics summary (?since=)
  GET /api/metrics/cost        Process metrics cost (?bead=&feature=&since=)
  GET /api/metrics/cycle-time  Process metrics cycle time (?since=)
  GET /api/metrics/rework      Process metrics rework (?since=)

MCP (POST /mcp):
  ddx_list_documents           List library documents
  ddx_read_document            Read a document
  ddx_search                   Full-text search
  ddx_resolve_persona          Resolve persona for a role
  ddx_list_beads               List beads
  ddx_show_bead                Show a specific bead
  ddx_bead_ready               List ready beads
  ddx_bead_status              Bead summary counts
  ddx_doc_graph                Document dependency graph
  ddx_doc_stale                Stale documents
  ddx_doc_show                 Document metadata
  ddx_doc_deps                 Upstream dependencies
  ddx_agent_sessions           List agent sessions`,
		RunE: func(cmd *cobra.Command, args []string) error {
			if err := f.checkLifecycleMigrationGate(cmd); err != nil {
				return err
			}
			if federationAllowPlainHTTP && !hubMode {
				return fmt.Errorf("--federation-allow-plain-http requires --hub-mode")
			}
			projectRoot := resolveProjectRoot("", f.WorkingDir)
			// Preflight: surface degraded startup diagnostics for missing lifecycle
			// skills or legacy symlinks without blocking server startup.
			preflightResult := checkProjectRuntimePreflight(projectRoot)
			emitServerPreflightDiagnostics(cmd.ErrOrStderr(), preflightResult)

			listenAddr := fmt.Sprintf("%s:%d", addr, port)
			fmt.Fprintf(cmd.OutOrStdout(), "DDx server listening on https://%s\n", listenAddr)
			srv := server.New(listenAddr, projectRoot)
			srv.EnableManagedWorkers()
			if hubMode {
				srv.EnableHubMode(federationAllowPlainHTTP)
				fmt.Fprintf(cmd.OutOrStdout(), "DDx hub-mode enabled (federation routes mounted)\n")
				if federationAllowPlainHTTP {
					fmt.Fprintf(cmd.OutOrStdout(), "WARNING: --federation-allow-plain-http is ON; non-ts-net peers may register\n")
				}
			}

			if strings.TrimSpace(hubURL) != "" {
				selfURL := federationSelfURL
				if selfURL == "" {
					selfURL = "https://" + listenAddr
				}
				if err := srv.EnableSpokeMode(cmd.Context(), hubURL, selfURL); err != nil {
					return fmt.Errorf("federation spoke registration failed: %w", err)
				}
				fmt.Fprintf(cmd.OutOrStdout(), "DDx spoke-mode enabled (registered with hub %s as %s)\n", hubURL, selfURL)
			}

			// Build tsnet config. tsnet is on by default — flags override config,
			// and --tsnet=false disables it. Hostname defaults to ddx-<hostname>.
			tc := &config.TsnetConfig{Enabled: true}
			if cfg, err := config.LoadWithWorkingDir(projectRoot); err == nil && cfg.Server != nil && cfg.Server.Tsnet != nil {
				*tc = *cfg.Server.Tsnet
			}
			if cmd.Flags().Changed("tsnet") {
				tc.Enabled = tsnetEnabled
			}
			// --no-tsnet is the discoverable opt-out for the default-on listener
			// and takes precedence over config and the positive --tsnet flag.
			if noTsnet, _ := cmd.Flags().GetBool("no-tsnet"); noTsnet {
				tc.Enabled = false
			}
			if tsnetHostname != "" {
				tc.Hostname = tsnetHostname
			}
			if tc.Hostname == "" {
				tc.Hostname = defaultTsnetHostname()
			}
			// Prefer TS_AUTHKEY env var; CLI flag is a fallback (secrets on CLI are visible in ps/history)
			tc.AuthKey = resolveTsnetAuthKey(os.Getenv("TS_AUTHKEY"), tsnetAuthKey, tc.AuthKey)
			if tc.Enabled {
				srv.TsnetConfig = tc
				fmt.Fprintf(cmd.OutOrStdout(), "DDx ts-net enabled (hostname: %s)\n", tc.Hostname)
			}

			if f.serverListenAndServeOverride != nil {
				return f.serverListenAndServeOverride(tlsCert, tlsKey)
			}
			return srv.ListenAndServeTLS(tlsCert, tlsKey)
		},
	}

	cmd.Flags().IntVarP(&port, "port", "p", 7743, "Port to listen on")
	cmd.Flags().StringVar(&addr, "addr", "127.0.0.1", "Address to bind to")
	cmd.Flags().StringVar(&tlsCert, "tls-cert", "", "TLS certificate file (PEM); auto-generates self-signed cert if omitted")
	cmd.Flags().StringVar(&tlsKey, "tls-key", "", "TLS private key file (PEM); auto-generates self-signed key if omitted")
	cmd.Flags().BoolVar(&tsnetEnabled, "tsnet", true, "Enable Tailscale ts-net listener (on by default; use --no-tsnet to disable; see ADR-006)")
	cmd.Flags().Bool("no-tsnet", false, "Disable the Tailscale ts-net listener (on by default; see ADR-006)")
	cmd.Flags().StringVar(&tsnetHostname, "tsnet-hostname", "", "Tailscale hostname (default: ddx-<hostname>)")
	cmd.Flags().StringVar(&tsnetAuthKey, "tsnet-auth-key", "", "Tailscale auth key for headless/CI use (SECURITY: visible in ps/history; prefer TS_AUTHKEY env var)")
	cmd.Flags().BoolVar(&hubMode, "hub-mode", false, "Run as a federation hub: mount /api/federation/* routes (FEAT-026)")
	cmd.Flags().BoolVar(&federationAllowPlainHTTP, "federation-allow-plain-http", false, "Accept federation registrations from non-loopback non-ts-net peers (hub-mode only; logs WARN on each accepted plain-HTTP registration)")
	cmd.Flags().StringVar(&hubURL, "hub-address", "", "Federation hub base URL to register with on startup (e.g. https://hub:7743). Enables spoke-mode (FEAT-026). Combine with --hub-mode for hub_spoke role.")
	cmd.Flags().StringVar(&federationSelfURL, "federation-self-url", "", "Self-URL advertised to the hub when --hub-address is set; defaults to https://<listen-addr>")

	// Worker management
	cmd.AddCommand(f.newServerWorkersCommand())

	// State file utilities (prune, …)
	cmd.AddCommand(f.newServerStateCommand())

	// Service management (systemd on Linux, launchd on macOS)
	cmd.AddCommand(f.newServerInstallCommand())
	cmd.AddCommand(f.newServerUninstallCommand())
	cmd.AddCommand(f.newServerStartCommand())
	cmd.AddCommand(f.newServerStopCommand())
	cmd.AddCommand(f.newServerStatusCommand())

	return cmd
}

package server

// Provider availability and utilization endpoints — FEAT-002 §26-27.
// Field semantics, unknown-state rules, and the zero-fabrication contract are
// governed by FEAT-014 (dashboard read model).

import (
	"context"
	"encoding/json"
	"net/http"
	"sort"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	agentlib "github.com/easel/fizeau"
)

// ---- Read-model types ----

// ProviderSummary is the list-response item for GET /api/providers.
// -1 sentinels on numeric fields mean unknown (FEAT-014 zero-fabrication).
type ProviderSummary struct {
	Harness            string   `json:"harness"`
	DisplayName        string   `json:"display_name"`
	Status             string   `json:"status"`         // available | unavailable | unknown
	AuthState          string   `json:"auth_state"`     // authenticated | unauthenticated | unknown
	QuotaHeadroom      string   `json:"quota_headroom"` // ok | blocked | unknown
	SignalSources      []string `json:"signal_sources"`
	FreshnessTS        string   `json:"freshness_ts,omitempty"`
	LastCheckedTS      string   `json:"last_checked_ts,omitempty"`
	RecentSuccessRate  float64  `json:"recent_success_rate"`   // -1 when sample_count < 3
	RecentLatencyP50MS int      `json:"recent_latency_p50_ms"` // -1 when unknown
	CostClass          string   `json:"cost_class"`
}

// ProviderModelQuota is per-model quota info within a provider detail.
type ProviderModelQuota struct {
	Model         string `json:"model"`
	QuotaHeadroom string `json:"quota_headroom"` // ok | blocked | unknown
	Source        string `json:"source"`
	SourceNote    string `json:"source_note,omitempty"`
}

// ProviderUsageWindow holds token/cost totals for one time window.
// -1 sentinel means unknown per FEAT-014 zero-fabrication contract.
type ProviderUsageWindow struct {
	InputTokens  int     `json:"input_tokens"`
	OutputTokens int     `json:"output_tokens"`
	TotalTokens  int     `json:"total_tokens"`
	CostUSD      float64 `json:"cost_usd"`
	CostNote     string  `json:"cost_note,omitempty"`
}

// ProviderHistoricalUsage holds 7d and 30d usage windows.
type ProviderHistoricalUsage struct {
	Window7D  *ProviderUsageWindow `json:"window_7d,omitempty"`
	Window30D *ProviderUsageWindow `json:"window_30d,omitempty"`
}

// ProviderBurnEstimate is the DDx-derived subscription-pressure estimate.
type ProviderBurnEstimate struct {
	DailyTokenRate   float64 `json:"daily_token_rate"`  // -1 when unknown
	SubscriptionBurn string  `json:"subscription_burn"` // low | moderate | high | unknown
	Source           string  `json:"source,omitempty"`
	Confidence       string  `json:"confidence"` // high | medium | low
	FreshnessTS      string  `json:"freshness_ts,omitempty"`
}

// ProviderPerformance holds DDx-observed latency/success metrics.
type ProviderPerformance struct {
	P50LatencyMS int     `json:"p50_latency_ms"` // -1 when unknown
	P95LatencyMS int     `json:"p95_latency_ms"` // -1 when unknown
	SuccessRate  float64 `json:"success_rate"`   // -1 when sample_count < 3
	SampleCount  int     `json:"sample_count"`
	Window       string  `json:"window"` // "7d"
}

// ProviderRoutingSignals is the routing signal summary within a provider detail.
type ProviderRoutingSignals struct {
	Availability string              `json:"availability"` // available | unavailable | unknown
	RequestFit   string              `json:"request_fit"`  // capable | unknown
	CostEstimate string              `json:"cost_estimate"`
	Performance  ProviderPerformance `json:"performance"`
}

// ProviderDetail is the response shape for GET /api/providers/{harness}.
type ProviderDetail struct {
	Harness         string                   `json:"harness"`
	DisplayName     string                   `json:"display_name"`
	Status          string                   `json:"status"`
	AuthState       string                   `json:"auth_state"`
	Models          []ProviderModelQuota     `json:"models"`
	HistoricalUsage *ProviderHistoricalUsage `json:"historical_usage,omitempty"`
	BurnEstimate    *ProviderBurnEstimate    `json:"burn_estimate,omitempty"`
	RoutingSignals  ProviderRoutingSignals   `json:"routing_signals"`
	SignalSources   []string                 `json:"signal_sources"`
	FreshnessTS     string                   `json:"freshness_ts,omitempty"`
}

// ---- HTTP handlers ----

// providerHandlerTimeout bounds the wall-clock cost of provider HTTP / MCP
// handlers so a slow subprocess inside fizeau's RouteStatus (e.g. the `pi`
// harness shelling out for --list-models when the binary is absent or
// unresponsive) cannot stall the request indefinitely. 10s mirrors
// handleAgentModels and is well below test-suite per-test budgets.
const providerHandlerTimeout = 10 * time.Second

// handleListProviders serves GET /api/providers — list all configured harnesses
// with routing availability, auth state, quota/headroom, and signal freshness.
// Not project-scoped; provider config is host+user global.
func (s *Server) handleListProviders(w http.ResponseWriter, r *http.Request) {
	ctx, cancel := context.WithTimeout(r.Context(), providerHandlerTimeout)
	defer cancel()

	now := time.Now().UTC()
	infos, err := listHarnessInfos(ctx, s.WorkingDir)
	if err != nil {
		writeJSON(w, http.StatusInternalServerError, map[string]string{"error": err.Error()})
		return
	}
	report := liveRouteStatusReport(ctx, s.WorkingDir)

	result := make([]ProviderSummary, 0, len(infos))
	for _, info := range infos {
		result = append(result, buildProviderSummary(info, report, now))
	}
	writeJSON(w, http.StatusOK, result)
}

// handleShowProvider serves GET /api/providers/{harness} — full routing signal
// snapshot per FEAT-014 read-model fields.
func (s *Server) handleShowProvider(w http.ResponseWriter, r *http.Request) {
	harnessName := r.PathValue("harness")
	if harnessName == "" {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": "harness required"})
		return
	}
	ctx, cancel := context.WithTimeout(r.Context(), providerHandlerTimeout)
	defer cancel()

	infos, err := listHarnessInfos(ctx, s.WorkingDir)
	if err != nil {
		writeJSON(w, http.StatusInternalServerError, map[string]string{"error": err.Error()})
		return
	}
	info, ok := findHarnessInfo(infos, harnessName)
	if !ok {
		writeJSON(w, http.StatusNotFound, map[string]string{"error": "harness not found"})
		return
	}

	now := time.Now().UTC()
	report := liveRouteStatusReport(ctx, s.WorkingDir)

	detail := buildProviderDetail(info, report, now)
	writeJSON(w, http.StatusOK, detail)
}

// ---- MCP tool implementations ----

func (s *Server) mcpProviderList() mcpToolResult {
	// Bound the ctx so the fizeau probe goroutines started inside
	// listHarnessInfos / liveRouteStatusReport are cancelled when the MCP
	// call returns. Without this they would inherit context.Background()
	// and leak for the lifetime of the server process. The timeout also
	// guards against a slow subprocess inside RouteStatus.
	ctx, cancel := context.WithTimeout(context.Background(), providerHandlerTimeout)
	defer cancel()

	now := time.Now().UTC()
	infos, err := listHarnessInfos(ctx, s.WorkingDir)
	if err != nil {
		return mcpToolResult{Content: []mcpContent{mcpText(err.Error())}, IsError: true}
	}

	report := liveRouteStatusReport(ctx, s.WorkingDir)

	result := make([]ProviderSummary, 0, len(infos))
	for _, info := range infos {
		result = append(result, buildProviderSummary(info, report, now))
	}
	data, err := json.Marshal(result)
	if err != nil {
		return mcpToolResult{Content: []mcpContent{mcpText("[]")}}
	}
	return mcpToolResult{Content: []mcpContent{mcpText(string(data))}}
}

func (s *Server) mcpProviderShow(harnessName string) mcpToolResult {
	if harnessName == "" {
		return mcpToolResult{Content: []mcpContent{mcpText("harness required")}, IsError: true}
	}
	// Bound the ctx so probe goroutines started inside listHarnessInfos /
	// liveRouteStatusReport terminate when the MCP call returns. The
	// timeout also guards against a slow subprocess inside RouteStatus.
	ctx, cancel := context.WithTimeout(context.Background(), providerHandlerTimeout)
	defer cancel()

	infos, err := listHarnessInfos(ctx, s.WorkingDir)
	if err != nil {
		return mcpToolResult{Content: []mcpContent{mcpText(err.Error())}, IsError: true}
	}
	info, ok := findHarnessInfo(infos, harnessName)
	if !ok {
		return mcpToolResult{Content: []mcpContent{mcpText("harness not found: " + harnessName)}, IsError: true}
	}

	now := time.Now().UTC()
	report := liveRouteStatusReport(ctx, s.WorkingDir)

	detail := buildProviderDetail(info, report, now)
	data, err := json.Marshal(detail)
	if err != nil {
		return mcpToolResult{Content: []mcpContent{mcpText("{}")}}
	}
	return mcpToolResult{Content: []mcpContent{mcpText(string(data))}}
}

package cmd

import (
	"testing"

	"github.com/stretchr/testify/assert"
)

// AC (ddx-b69f04f8): the spoke-mode CLI exposes --hub-address as the
// hub URL flag. Pin the name so a future rename triggers a test failure
// rather than silently breaking systemd units / scripts that use it.
func TestServerCommandExposesHubAddressFlag(t *testing.T) {
	f := &CommandFactory{WorkingDir: t.TempDir()}
	cmd := f.newServerCommand()

	flag := cmd.Flags().Lookup("hub-address")
	if flag == nil {
		t.Fatalf("server command missing --hub-address flag")
	}
	if flag.Value.Type() != "string" {
		t.Errorf("--hub-address should be a string flag, got %q", flag.Value.Type())
	}
	if flag.DefValue != "" {
		t.Errorf("--hub-address default should be empty, got %q", flag.DefValue)
	}

	// The legacy --hub flag must not exist; we renamed to --hub-address.
	if cmd.Flags().Lookup("hub") != nil {
		t.Errorf("legacy --hub flag should be removed in favour of --hub-address")
	}
}

func TestResolveTsnetAuthKey(t *testing.T) {
	tests := []struct {
		name      string
		envKey    string
		flagKey   string
		configKey string
		want      string
	}{
		{
			name:      "env var overrides CLI flag",
			envKey:    "env-key",
			flagKey:   "flag-key",
			configKey: "",
			want:      "env-key",
		},
		{
			name:      "env var overrides config file",
			envKey:    "env-key",
			flagKey:   "",
			configKey: "config-key",
			want:      "env-key",
		},
		{
			name:      "env var overrides both CLI flag and config file",
			envKey:    "env-key",
			flagKey:   "flag-key",
			configKey: "config-key",
			want:      "env-key",
		},
		{
			name:      "CLI flag overrides config file when env var absent",
			envKey:    "",
			flagKey:   "flag-key",
			configKey: "config-key",
			want:      "flag-key",
		},
		{
			name:      "config file used when env var and flag absent",
			envKey:    "",
			flagKey:   "",
			configKey: "config-key",
			want:      "config-key",
		},
		{
			name:      "empty result when all sources absent",
			envKey:    "",
			flagKey:   "",
			configKey: "",
			want:      "",
		},
	}

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			got := resolveTsnetAuthKey(tc.envKey, tc.flagKey, tc.configKey)
			assert.Equal(t, tc.want, got)
		})
	}
}

