	if c == nil || c.Intake == nil || c.Intake.ACQuality == nil || c.Intake.ACQuality.MinScore == nil {
		return defaultACQualityMinScore
	}
	s := *c.Intake.ACQuality.MinScore
	if s < 0 || s > 1 {
		return defaultACQualityMinScore
	}
	return s
}

